const html = "<!DOCTYPE html>
<html lang="pt-BR">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Relatório Financeiro PRN</title>
<style>
*,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
body{font-family:'Segoe UI',Tahoma,Geneva,Verdana,sans-serif;background:#f0f2f5;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:20px;color:#1a1a2e}
.container{background:#fff;border-radius:12px;box-shadow:0 4px 24px rgba(0,0,0,.08);width:100%;max-width:520px;padding:40px 36px}
.header{text-align:center;margin-bottom:32px}
.header h1{font-size:1.6rem;font-weight:700;color:#1a3a5c;margin-bottom:8px;letter-spacing:-.3px}
.header p{font-size:.92rem;color:#6b7a8d;line-height:1.5}
.form-group{margin-bottom:22px}
.form-group label{display:block;font-size:.85rem;font-weight:600;color:#2c3e50;margin-bottom:8px}
.form-group label .required{color:#e74c3c;margin-left:2px}
.file-upload-wrapper{position:relative}
.file-upload-wrapper input[type="file"]{display:none}
.file-upload-btn{display:flex;align-items:center;justify-content:center;gap:10px;width:100%;padding:18px 16px;border:2px dashed #b0c4d8;border-radius:8px;background:#f8fafc;color:#4a6fa5;font-size:.9rem;font-weight:500;cursor:pointer;transition:all .2s ease}
.file-upload-btn:hover{border-color:#2e6da4;background:#eef3f9}
.file-upload-btn svg{width:22px;height:22px;flex-shrink:0}
.file-upload-btn .file-name{font-weight:600;color:#1a3a5c;text-align:center;word-break:break-all}
.file-upload-btn.has-file{border-color:#27ae60;border-style:solid;background:#f0faf4;color:#1e8449}
.file-upload-btn.has-file svg{color:#27ae60}
.file-size-error{font-size:.8rem;color:#e74c3c;margin-top:6px;display:none}
.date-input{width:100%;padding:12px 14px;border:1.5px solid #cdd6e0;border-radius:8px;font-size:.9rem;color:#2c3e50;background:#f8fafc;transition:border-color .2s ease;font-family:inherit}
.date-input:focus{outline:none;border-color:#2e6da4;background:#fff}
.submit-btn{width:100%;padding:15px;background:linear-gradient(135deg,#1a5276,#2e86c1);color:#fff;border:none;border-radius:8px;font-size:1rem;font-weight:600;cursor:pointer;transition:all .2s ease;margin-top:8px;letter-spacing:.2px}
.submit-btn:hover{background:linear-gradient(135deg,#154360,#2471a3);transform:translateY(-1px);box-shadow:0 4px 12px rgba(26,82,118,.3)}
.submit-btn:active{transform:translateY(0)}
.submit-btn:disabled{background:#95a5b6;cursor:not-allowed;transform:none;box-shadow:none}
.spinner{display:inline-block;width:18px;height:18px;border:2.5px solid rgba(255,255,255,.3);border-top-color:#fff;border-radius:50%;animation:spin .7s linear infinite;margin-right:8px;vertical-align:middle}
@keyframes spin{to{transform:rotate(360deg)}}
.error-message{background:#fef2f2;border:1px solid #f5c6cb;border-radius:8px;padding:14px 16px;margin-top:20px;display:none}
.error-message .error-title{font-weight:600;color:#c0392b;font-size:.88rem;margin-bottom:4px}
.error-message .error-text{font-size:.84rem;color:#721c24;line-height:1.5}
.footer{text-align:center;margin-top:28px;font-size:.78rem;color:#95a5b6}
@media(max-width:560px){
  .container{padding:28px 20px;border-radius:10px}
  .header h1{font-size:1.3rem}
  .file-upload-btn{padding:14px 12px;font-size:.85rem}
}
</style>
</head>
<body>
<div class="container">
  <div class="header">
    <h1>Relatório Financeiro PRN</h1>
    <p>Upload das planilhas para geração do relatório</p>
  </div>

  <form id="reportForm" method="POST" enctype="multipart/form-data" action="https://prndiag1.app.n8n.cloud/webhook/prn/report" novalidate>
    <div class="form-group">
      <label>Planilha Diária <span class="required">*</span></label>
      <div class="file-upload-wrapper">
        <div class="file-upload-btn" id="dailyDropZone" tabindex="0" role="button" aria-label="Selecionar Planilha Diária">
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/></svg>
          <span id="dailyLabel">Clique ou arraste a planilha (.xlsx)</span>
        </div>
        <input type="file" id="dailyFile" name="daily_file" accept=".xlsx">
      </div>
      <div class="file-size-error" id="dailySizeError">O arquivo excede o limite de 10MB.</div>
    </div>

    <div class="form-group">
      <label>Planilha Histórica PRN <span class="required">*</span></label>
      <div class="file-upload-wrapper">
        <div class="file-upload-btn" id="historicalDropZone" tabindex="0" role="button" aria-label="Selecionar Planilha Histórica PRN">
          <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" stroke-width="2"><path stroke-linecap="round" stroke-linejoin="round" d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12"/></svg>
          <span id="historicalLabel">Clique ou arraste a planilha (.xlsx)</span>
        </div>
        <input type="file" id="historicalFile" name="historical_file" accept=".xlsx">
      </div>
      <div class="file-size-error" id="historicalSizeError">O arquivo excede o limite de 10MB.</div>
    </div>

    <div class="form-group">
      <label for="referenceDate">Data de Referência <span style="color:#95a5b6;font-weight:400">(opcional)</span></label>
      <input type="date" id="referenceDate" name="reference_date" class="date-input">
    </div>

    <button type="submit" class="submit-btn" id="submitBtn">Gerar Relatório</button>
  </form>

  <div class="error-message" id="errorMessage">
    <div class="error-title">Erro ao processar</div>
    <div class="error-text" id="errorText"></div>
  </div>

  <div class="footer">Sistema de Relatórios Financeiros</div>
</div>

<script>
(function() {
  var MAX_SIZE = 10 * 1024 * 1024;
  var dailyFileInput = document.getElementById('dailyFile');
  var historicalFileInput = document.getElementById('historicalFile');
  var dailyDropZone = document.getElementById('dailyDropZone');
  var historicalDropZone = document.getElementById('historicalDropZone');
  var dailyLabel = document.getElementById('dailyLabel');
  var historicalLabel = document.getElementById('historicalLabel');
  var dailySizeError = document.getElementById('dailySizeError');
  var historicalSizeError = document.getElementById('historicalSizeError');
  var form = document.getElementById('reportForm');
  var submitBtn = document.getElementById('submitBtn');
  var errorMessage = document.getElementById('errorMessage');
  var errorText = document.getElementById('errorText');

  function handleFileSelect(input, dropZone, label, sizeError) {
    input.addEventListener('change', function() {
      sizeError.style.display = 'none';
      if (input.files && input.files.length > 0) {
        var file = input.files[0];
        if (file.size > MAX_SIZE) {
          input.value = '';
          label.textContent = 'Clique ou arraste a planilha (.xlsx)';
          dropZone.classList.remove('has-file');
          sizeError.style.display = 'block';
          return;
        }
        label.textContent = file.name;
        dropZone.classList.add('has-file');
      } else {
        label.textContent = 'Clique ou arraste a planilha (.xlsx)';
        dropZone.classList.remove('has-file');
      }
    });

    dropZone.addEventListener('click', function() { input.click(); });
    dropZone.addEventListener('keydown', function(e) {
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); input.click(); }
    });

    dropZone.addEventListener('dragover', function(e) { e.preventDefault(); dropZone.style.borderColor = '#2e86c1'; });
    dropZone.addEventListener('dragleave', function(e) {
      e.preventDefault();
      dropZone.style.borderColor = dropZone.classList.contains('has-file') ? '#27ae60' : '#b0c4d8';
    });
    dropZone.addEventListener('drop', function(e) {
      e.preventDefault();
      dropZone.style.borderColor = '';
      var files = e.dataTransfer.files;
      if (files.length > 0) {
        input.files = files;
        input.dispatchEvent(new Event('change'));
      }
    });
  }

  handleFileSelect(dailyFileInput, dailyDropZone, dailyLabel, dailySizeError);
  handleFileSelect(historicalFileInput, historicalDropZone, historicalLabel, historicalSizeError);

  function showError(msg) {
    errorText.textContent = msg;
    errorMessage.style.display = 'block';
  }

  form.addEventListener('submit', function(e) {
    e.preventDefault();
    errorMessage.style.display = 'none';
    dailySizeError.style.display = 'none';
    historicalSizeError.style.display = 'none';

    if (!dailyFileInput.files || dailyFileInput.files.length === 0) {
      showError('Selecione a Planilha Diária para continuar.');
      return;
    }
    if (!historicalFileInput.files || historicalFileInput.files.length === 0) {
      showError('Selecione a Planilha Histórica PRN para continuar.');
      return;
    }
    if (dailyFileInput.files[0].size > MAX_SIZE) {
      dailySizeError.style.display = 'block';
      return;
    }
    if (historicalFileInput.files[0].size > MAX_SIZE) {
      historicalSizeError.style.display = 'block';
      return;
    }

    submitBtn.disabled = true;
    submitBtn.innerHTML = '<span class="spinner"></span>Processando...';

    form.submit();
  });
})();
</script>
</body>
</html>
";
return [{ json: { html } }];

const item = $input.first() || {};
const binary = item.binary || {};
const errors = [];

if (!binary.daily_file) {
  errors.push('Planilha Diária não enviada (campo daily_file).');
}
if (!binary.historical_file) {
  errors.push('Planilha Histórica PRN não enviada (campo historical_file).');
}

const crypto = require('crypto');
const requestId = crypto.randomUUID
  ? crypto.randomUUID()
  : `req_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const rawRef = String(item.json?.reference_date || item.json?.referenceDate || '').trim();
const isISODate = /^\d{4}-\d{2}-\d{2}$/.test(rawRef);
const referenceDateUsed = isISODate ? rawRef : new Date().toISOString().slice(0, 10);

if (errors.length > 0) {
  return [{
    json: {
      valid: false,
      requestId,
      errorCode: 'VALIDATION_ERROR',
      error: 'Falha na validação do upload.',
      details: { errors },
    },
  }];
}

return [{
  json: {
    kind: 'context',
    valid: true,
    requestId,
    referenceDateUsed,
    dailyFilename: binary.daily_file?.fileName || 'daily.xlsx',
    historyFilename: binary.historical_file?.fileName || 'history.xlsx',
  },
  binary,
}];

const inputItems = $input.all();
const warnings = [];
const blockingErrors = [];

if (inputItems.some((it) => it.json?.error)) {
  blockingErrors.push('Falha ao extrair a aba Contas. Verifique se a aba existe e está legível.');
}

const rows = inputItems
  .map((it) => (Array.isArray(it.json?.row) ? it.json.row : null))
  .filter((r) => Array.isArray(r));

if (rows.length === 0) {
  blockingErrors.push('Aba Contas sem linhas utilizáveis.');
  return [{ json: { kind: 'contas', contas: [], warnings, blockingErrors } }];
}

const t = (v) => (v == null ? '' : String(v).trim());
const tu = (v) => t(v).toUpperCase();

const toNumber = (v) => {
  if (v == null || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? Math.round(v * 100) / 100 : null;
  let s = String(v).trim();
  s = s.replace(/\s+/g, '');
  if (s.includes(',') && s.includes('.')) {
    s = s.replace(/\./g, '').replace(',', '.');
  } else if (s.includes(',')) {
    s = s.replace(',', '.');
  }
  const n = Number(s);
  return Number.isFinite(n) ? Math.round(n * 100) / 100 : null;
};

const toDate = (v) => {
  if (v == null || v === '') return null;
  if (typeof v === 'number' && Number.isFinite(v)) {
    // Excel serial date (base 1899-12-30)
    const wholeDays = Math.floor(v);
    const excelEpoch = Date.UTC(1899, 11, 30);
    const d = new Date(excelEpoch + wholeDays * 86400000);
    if (!Number.isNaN(d.getTime())) return d.toISOString().slice(0, 10);
  }
  if (Object.prototype.toString.call(v) === '[object Date]' && !Number.isNaN(v.getTime())) {
    return v.toISOString().slice(0, 10);
  }
  const s = String(v).trim();
  if (/^\d+(\.\d+)?$/.test(s)) {
    const asNum = Number(s);
    if (Number.isFinite(asNum) && asNum > 20000 && asNum < 90000) {
      const wholeDays = Math.floor(asNum);
      const excelEpoch = Date.UTC(1899, 11, 30);
      const d = new Date(excelEpoch + wholeDays * 86400000);
      if (!Number.isNaN(d.getTime())) return d.toISOString().slice(0, 10);
    }
  }
  const dmy = s.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (dmy) {
    const dd = dmy[1].padStart(2, '0');
    const mm = dmy[2].padStart(2, '0');
    return `${dmy[3]}-${mm}-${dd}`;
  }

  const isoLike = s.match(/^(\d{4})[-/](\d{1,2})[-/](\d{1,2})(?:[T\s].*)?$/);
  if (isoLike) {
    const yyyy = isoLike[1];
    const mm = isoLike[2].padStart(2, '0');
    const dd = isoLike[3].padStart(2, '0');
    const d = new Date(`${yyyy}-${mm}-${dd}T00:00:00Z`);
    if (!Number.isNaN(d.getTime())) return `${yyyy}-${mm}-${dd}`;
  }

  return null;
};

let headerIndex = -1;
for (let i = 0; i < Math.min(rows.length, 30); i++) {
  const c = rows[i].slice(0, 7).map(tu);
  const hasVenc = c.some((x) => x.includes('VENC'));
  const hasFav = c.some((x) => x.includes('FAVOREC') || x.includes('FORNECEDOR') || x.includes('DESCRI'));
  const hasVal = c.some((x) => x === 'VALOR' || x.includes('VALOR'));
  if (hasVenc && hasFav && hasVal) {
    headerIndex = i;
    break;
  }
}

const header = headerIndex >= 0 ? rows[headerIndex].slice(0, 7).map(tu) : [];

const idx = {
  venc: 0,
  fav: 1,
  dep: 2,
  cat: 3,
  val: 4,
  parcela: 5,
  obs: 6,
};

if (header.length) {
  for (let i = 0; i < header.length; i++) {
    const h = header[i];
    if (h.includes('VENC')) idx.venc = i;
    if (h.includes('FAVOREC') || h.includes('FORNECEDOR') || h.includes('DESCRI')) idx.fav = i;
    if (h.includes('DEPART') || h.includes('SETOR')) idx.dep = i;
    if (h.includes('CATEG')) idx.cat = i;
    if (h.includes('VALOR')) idx.val = i;
    if (h.includes('PARCEL')) idx.parcela = i;
    if (h.includes('OBS')) idx.obs = i;
  }
}

const start = headerIndex >= 0 ? headerIndex + 1 : 2;
const contas = [];

for (let i = start; i < rows.length; i++) {
  const r = rows[i];
  const firstBlock = r.slice(0, 7);
  const joined = firstBlock.map(tu).join(' ');

  if (joined.includes('CAMBORIU') || joined.includes('PALHOCA')) continue;
  if (firstBlock.every((x) => t(x) === '')) continue;

  const favorecido = t(firstBlock[idx.fav]);
  const favorecidoU = favorecido.toUpperCase();
  const categoria = t(firstBlock[idx.cat]);
  const valor = toNumber(firstBlock[idx.val]);

  if (!favorecido && !categoria && (valor == null || valor === 0)) continue;
  if (!favorecido) continue;
  if (/^(TOTAL|SALDO|DESPESA|DESPESAS|TRANSFERENCIA|TRANSFERÊNCIA|APLICA)/.test(favorecidoU)) continue;
  if (favorecidoU === 'N/D') continue;
  if (valor == null) {
    warnings.push(`Linha ${i + 1} ignorada na aba Contas: valor inválido.`);
    continue;
  }

  contas.push({
    entity: 'prn_matriz',
    vencimento: toDate(firstBlock[idx.venc]),
    favorecido: favorecido || 'N/D',
    departamento: t(firstBlock[idx.dep]) || null,
    categoria: categoria || 'Sem categoria',
    valor,
    parcela: t(firstBlock[idx.parcela]) || null,
    observacao: t(firstBlock[idx.obs]) || null,
    contaCorrente: null,
  });
}

if (contas.length === 0) {
  warnings.push('Nenhuma despesa válida encontrada na aba Contas (bloco PRN MATRIZ).');
}

return [{ json: { kind: 'contas', contas, warnings, blockingErrors } }];

const inputItems = $input.all();
const warnings = [];
const blockingErrors = [];

if (inputItems.some((it) => it.json?.error)) {
  blockingErrors.push('Falha ao extrair a aba Recebido. Verifique se a aba existe e está legível.');
}

const rows = inputItems
  .map((it) => (Array.isArray(it.json?.row) ? it.json.row : null))
  .filter((r) => Array.isArray(r));

if (rows.length === 0) {
  blockingErrors.push('Aba Recebido sem linhas utilizáveis.');
  return [{ json: { kind: 'recebido', recebido: [], warnings, blockingErrors } }];
}

const t = (v) => (v == null ? '' : String(v).trim());
const tu = (v) => t(v).toUpperCase();

const toNumber = (v) => {
  if (v == null || v === '') return null;
  if (typeof v === 'number') return Number.isFinite(v) ? Math.round(v * 100) / 100 : null;
