  pago_parcialmente: 'Pago Parcialmente',
  pendente: 'Pendente',
  cancelado: 'Cancelado',
};

// Set of known entity codes for filtering recebido records.
const PRN_ENTITY_CODES = new Set([
  'prn_matriz',
  'prn_locacao',
  'prn_holding',
]);

// =============================================================================
// Lookup Helpers
// =============================================================================

/**
 * Looks up a value in an alias map using case/accent-insensitive matching.
 * Returns the canonical code, or the original input trimmed if no match.
 */
function resolveAlias(raw, aliasMap) {
  if (!raw || typeof raw !== 'string') return null;
  const key = raw.trim().toLowerCase();
  return aliasMap[key] || null;
}

/**
 * Normalizes a bank account name: returns the canonical code.
 */
function normalizeBank(raw) {
  return resolveAlias(raw, BANK_ALIASES);
}

/**
 * Normalizes an entity name: returns the canonical code.
 */
function normalizeEntity(raw) {
  return resolveAlias(raw, ENTITY_ALIASES);
}

/**
 * Normalizes a category name: returns the canonical code.
 */
function normalizeCategory(raw) {
  return resolveAlias(raw, CATEGORY_ALIASES);
}

/**
 * Normalizes a payment status: returns the canonical code.
 */
function normalizeStatus(raw) {
  return resolveAlias(raw, STATUS_ALIASES);
}

// =============================================================================
// Date Helpers
// =============================================================================

/**
 * Attempts to parse a date value into an ISO string.
 * Accepts Date objects, ISO strings, or Brazilian "dd/mm/yyyy" strings.
 * Returns null if unparseable.
 */
function toISODate(value) {
  if (!value) return null;
  if (value instanceof Date) {
    return isNaN(value.getTime()) ? null : value.toISOString().slice(0, 10);
  }
  if (typeof value !== 'string') return null;

  const trimmed = value.trim();
  if (!trimmed) return null;

  // Numeric strings are treated as Excel serial dates when plausible.
  // Plain year-like strings (e.g. "2502") are rejected to avoid false positives.
  if (/^\d+(\.\d+)?$/.test(trimmed)) {
    const asNum = Number(trimmed);
    if (Number.isFinite(asNum) && asNum > 20000 && asNum < 90000) {
      const wholeDays = Math.floor(asNum);
      const excelEpoch = Date.UTC(1899, 11, 30);
      const date = new Date(excelEpoch + wholeDays * 86400000);
      return isNaN(date.getTime()) ? null : date.toISOString().slice(0, 10);
    }
    return null;
  }

  // Try native ISO parse first
  const isoLike = trimmed.match(/^(\d{4})[-/](\d{1,2})[-/](\d{1,2})(?:[T\s].*)?$/);
  if (isoLike) {
    const [, year, month, day] = isoLike;
    const parsed = new Date(Date.UTC(Number(year), Number(month) - 1, Number(day)));
    if (!isNaN(parsed.getTime())) {
      return parsed.toISOString().slice(0, 10);
    }
  }

  // Try Brazilian dd/mm/yyyy or dd/mm/yyyy hh:mm
  const brMatch = trimmed.match(/^(\d{1,2})[/\-.](\d{1,2})[/\-.](\d{4})/);
  if (brMatch) {
    const [, day, month, year] = brMatch;
    const parsed = new Date(Date.UTC(Number(year), Number(month) - 1, Number(day)));
    if (!isNaN(parsed.getTime())) {
      return parsed.toISOString().slice(0, 10);
    }
  }

  // Last resort only for clearly date-like strings.
  if (/[\-/:T]/.test(trimmed)) {
    const native = new Date(trimmed);
    if (!isNaN(native.getTime())) {
      return native.toISOString().slice(0, 10);
    }
  }

  return null;
}

// =============================================================================
// Value Helpers
// =============================================================================

/**
 * Coerces a value to a number. Handles string numbers with common
 * Brazilian formatting (dot as thousands separator, comma as decimal).
 * Returns NaN if unparseable.
 */
function toNumber(value) {
  if (value === null || value === undefined || value === '') return NaN;
  if (typeof value === 'number') return value;

  if (typeof value === 'string') {
    // Remove R$ prefix, spaces, and common currency symbols
    let cleaned = value
      .replace(/[R$\s]/g, '')
      .replace(/\.(?=\d{3})/g, '')   // remove thousands separators (dots)
      .replace(/,/g, '.');            // decimal comma -> dot

    // Handle edge case where cleaned string ends with a dot
    cleaned = cleaned.replace(/\.$/, '');

    const parsed = Number(cleaned);
    return isNaN(parsed) ? NaN : parsed;
  }

  return NaN;
}

/**
 * Trims a string value, or returns null for falsy input.
 */
function trimText(value) {
  if (!value || typeof value !== 'string') return null;
  return value.trim();
}

// =============================================================================
// Warning Helpers
// =============================================================================

/**
 * Creates a normalization warning object.
 */
function makeWarning(source, field, rawValue, message) {
  return {
    severity: 'low',
    source: `normalizer:${source}`,
    field,
    raw: rawValue ?? null,
    message,
  };
}

// =============================================================================
// Build Entity Summaries
// =============================================================================

/**
 * Builds the entities array from the daily resumo data.
 * Each entity gets its bank balance, applications, expenses total,
 * and received total from the parsed summary.
 */
function buildEntities(resumo, warnings) {
  const entityCodes = ['prn_matriz', 'prn_locacao', 'prn_holding'];
  const entities = [];

  for (const code of entityCodes) {
    const raw = resumo?.[code] || {};
    const label = ENTITY_LABELS[code] || code;

    entities.push({
      code,
      label,
      saldoBancario: toNumber(raw.saldos) || 0,
      saldoAplicacoes: toNumber(raw.aplicacoes) || 0,
      despesas: toNumber(raw.despesas) || 0,
      recebido: toNumber(raw.recebido) || 0,
    });
  }

  return entities;
}

// =============================================================================
// Normalize Expenses (Contas a Pagar)
// =============================================================================

/**
 * Normalizes the daily contas array into the canonical expense format.
 * Attempts to resolve entity, bank, and category from the raw record.
 */
function normalizeExpenses(contas, warnings) {
  if (!Array.isArray(contas)) return [];

  let categoryWarningCount = 0;

  return contas.map((item, idx) => {
    const entity = normalizeEntity(item.empresa || item.entidade || item.favorecido);
    const contaCorrenteRaw = trimText(item.contaCorrente || item.conta_corrente || item.banco);
    const contaCorrente = normalizeBank(contaCorrenteRaw);
    const categoriaRaw = trimText(item.categoria || item.categoria_descricao);
    const categoria = normalizeCategory(categoriaRaw);

    // Warn about unresolvable aliases
    if (!entity && contaCorrenteRaw) {
      // Only warn if there is context suggesting an entity was intended
    }
    if (contaCorrenteRaw && !contaCorrente) {
      warnings.push(
        makeWarning('expenses', 'contaCorrente', contaCorrenteRaw,
          `Unknown bank alias "${contaCorrenteRaw}" at index ${idx}`)
      );
    }
    if (categoriaRaw && !categoria && categoriaRaw.toLowerCase() !== 'sem categoria' && categoryWarningCount < 10) {
      categoryWarningCount += 1;
      warnings.push(
        makeWarning('expenses', 'categoria', categoriaRaw,
          `Unknown category alias "${categoriaRaw}" at index ${idx}`)
      );
    }

    return {
      entity: entity || null,
      vencimento: toISODate(item.vencimento),
      favorecido: trimText(item.favorecido) || trimText(item.fornecedor),
      categoria,
      categoriaOriginal: categoriaRaw,
      departamento: trimText(item.departamento),
      valor: toNumber(item.valor) || 0,
      parcela: trimText(item.parcela),
      contaCorrente: contaCorrente || null,
      contaCorrenteOriginal: contaCorrenteRaw,
      observacao: trimText(item.observacao) || trimText(item.obs) || trimText(item.descricao),
    };
  });
}

// =============================================================================
// Normalize Receipts (Recebido)
// =============================================================================

/**
 * Normalizes the daily recebido array.
 * Filters to only records belonging to PRN entities.
 */
function normalizeReceipts(recebido, warnings) {
  if (!Array.isArray(recebido)) return [];

  const filtered = recebido.filter((item) => {
    const empresa = trimText(item.empresa) || '';
    const code = normalizeEntity(empresa);

    if (code && PRN_ENTITY_CODES.has(code)) {
      return true;
    }

    // If isPrn flag is explicitly set, include it regardless of entity name
    if (item.isPrn === true || item.isPrn === 'true' || item.isPrn === 1) {
      return true;
    }

    return false;
  });

  return filtered.map((item, idx) => {
    const empresa = trimText(item.empresa) || '';
    const entity = normalizeEntity(empresa) || null;
    const contaCorrenteRaw = trimText(item.contaCorrente || item.conta_corrente || item.banco);
    const contaCorrente = normalizeBank(contaCorrenteRaw);
    const categoriaRaw = trimText(item.categoria);

    if (contaCorrenteRaw && !contaCorrente) {
      warnings.push(
        makeWarning('receipts', 'contaCorrente', contaCorrenteRaw,
          `Unknown bank alias "${contaCorrenteRaw}" at index ${idx}`)
      );
    }

    return {
      entity,
      data: toISODate(item.data),
      descricao: trimText(item.descricao),
      contaCorrente: contaCorrente || null,
      contaCorrenteOriginal: contaCorrenteRaw,
      valor: toNumber(item.valor) || 0,
      categoria: normalizeCategory(categoriaRaw),
      categoriaOriginal: categoriaRaw,
      conciliado: item.conciliado === true || item.conciliado === 'true' || item.conciliado === 1,
    };
  });
}

// =============================================================================
// Build Balances
// =============================================================================

/**
 * Builds the balances array from entity summaries.
 * Each entity's saldoBancario is attributed to the "default" bank group.
 */
function buildBalances(entities) {
  const balances = [];

  for (const entity of entities) {
    // If the entity has bank-level breakdowns in resumo, use those.
    // Otherwise, report saldoBancario as a single entry.
    if (entity.saldoBancario !== 0 || entity.saldoAplicacoes !== 0) {
      balances.push({
        entity: entity.code,
        contaCorrente: 'total',
        saldo: entity.saldoBancario + entity.saldoAplicacoes,
      });
    }
  }

  return balances;
}

// =============================================================================
// Normalize History
// =============================================================================

/**
 * Normalizes the history rows and builds a summary.
 */
function normalizeHistory(history) {
  if (!history || !history.rows) {
    return {
      rows: [],
      summary: {
        totalRecords: 0,
        periodStart: null,
        periodEnd: null,
        totalPago: 0,
        totalAtrasado: 0,
      },
    };
  }

  const normalizedRows = history.rows.map((row) => {
    const contaCorrenteRaw = trimText(row.contaCorrente || row.conta_corrente || row.banco);
    const contaCorrente = normalizeBank(contaCorrenteRaw);
    const categoriaRaw = trimText(row.categoria);

    return {
      situacao: normalizeStatus(row.situacao || row.status) || trimText(row.situacao),
      situacaoOriginal: trimText(row.situacao) || trimText(row.status),
      fornecedor: trimText(row.fornecedor) || trimText(row.favorecido),
      previsao: toISODate(row.previsao),
      ultimoPagamento: toISODate(row.ultimoPagamento || row.ultimo_pagamento),
      valorLiquido: toNumber(row.valorLiquido || row.valor_liquido || row.valor) || 0,
      categoria: normalizeCategory(categoriaRaw),
      categoriaOriginal: categoriaRaw,
      contaCorrente: contaCorrente || null,
      contaCorrenteOriginal: contaCorrenteRaw,
      vencimento: toISODate(row.vencimento),
    };
  });

  // Build summary by aggregating normalized rows
  let totalPago = 0;
  let totalAtrasado = 0;
  let periodStart = null;
  let periodEnd = null;

  for (const row of normalizedRows) {
    const situacao = row.situacao;
    if (situacao === 'pago' || situacao === 'pago_parcialmente') {
      totalPago += row.valorLiquido;
    }
    if (situacao === 'atrasado') {
      totalAtrasado += row.valorLiquido;
    }

    const venc = row.vencimento;
    if (venc) {
      if (!periodStart || venc < periodStart) periodStart = venc;
      if (!periodEnd || venc > periodEnd) periodEnd = venc;
    }
  }

  return {
    rows: normalizedRows,
    summary: {
      totalRecords: normalizedRows.length,
      periodStart,
      periodEnd,
      totalPago: Math.round(totalPago * 100) / 100,
      totalAtrasado: Math.round(totalAtrasado * 100) / 100,
    },
  };
}

// =============================================================================
// Main Normalizer Function
// =============================================================================

/**
 * Normalizes raw parsed data from parser-daily.js and parser-history.js.
 *
 * @param {Object} rawData - Raw parsed data with `daily` and `history` keys.
 * @returns {Object} Normalized data with entities, expenses, receipts, balances,
 *                   history, and warnings.
 */
function normalizeData(rawData) {
  const warnings = [];

  // Collect warnings from both parsers if present
  const dailyWarnings = rawData?.daily?.warnings || [];
  const historyWarnings = rawData?.history?.warnings || [];

  for (const w of dailyWarnings) {
    warnings.push({
      severity: w.severity || 'low',
      source: w.source || 'parser:daily',
      field: w.field || null,
      raw: w.raw ?? null,
      message: w.message || String(w),
    });
  }

  for (const w of historyWarnings) {
    warnings.push({
      severity: w.severity || 'low',
      source: w.source || 'parser:history',
      field: w.field || null,
      raw: w.raw ?? null,
      message: w.message || String(w),
    });
  }

  // Build entities from daily resumo
  const entities = buildEntities(rawData?.daily?.resumo, warnings);

  // Normalize expenses (contas a pagar)
  const expenses = normalizeExpenses(rawData?.daily?.contas, warnings);

  // Normalize receipts (recebido) - filtered to PRN entities only
  const receipts = normalizeReceipts(rawData?.daily?.recebido, warnings);

  // Build balances from entities
  const balances = buildBalances(entities);

  // Normalize history rows and summary
  const history = normalizeHistory(rawData?.history);

  return {
    entities,
    expenses,
    receipts,
    balances,
    history,
    warnings,
  };
}

// =============================================================================
// Exports
// =============================================================================

/**
 * calculator.js - Financial Calculation Engine for PRN Reporting
 *
 * Receives normalized data from normalizer.js and performs all financial
 * calculations needed for the n8n reporting workflow.
 *
 * Input: normalizedData object (see normalizer.js output schema)
 * Output: { summary, topDespesas, despesasPorCategoria, recebidosPorConta, historyAnalysis, warnings }
 */

// --- Helpers ---

/**
 * Rounds a numeric value to 2 decimal places.
 * Uses a multiplier trick to avoid floating-point precision issues.
 * @param {number} value
 * @returns {number}
 */
function round2(value) {
  if (typeof value !== 'number' || isNaN(value)) return 0;
  return Math.round((value + Number.EPSILON) * 100) / 100;
}

/**
 * Safely reads a numeric property, defaulting to 0 if missing or non-numeric.
 * @param {object} obj
 * @param {string} prop
 * @returns {number}
 */
function numProp(obj, prop) {
  const raw = obj[prop];
  if (typeof raw === 'number' && !isNaN(raw)) return raw;
  if (typeof raw === 'string') {
    const parsed = parseFloat(raw.replace(/[^\d.,-]/g, '').replace(',', '.'));
    return isNaN(parsed) ? 0 : parsed;
  }
  return 0;
}

/**
 * Groups an array of objects by a given key, then reduces with a custom
 * accumulator function to produce { [key]: accumulated }.
 *
 * @param {Array} items       - Array of row objects.
 * @param {string} groupKey   - Property name to group by.
 * @param {string} sumKey     - Property name whose numeric values are summed.
 * @returns {Object}          - { groupValue: { total, count } }
 */
function groupAndSum(items, groupKey, sumKey) {
  const groups = {};

  for (const item of items) {
    const key = String(item[groupKey] || 'Indefinido').trim();
    const value = round2(numProp(item, sumKey));

    if (!groups[key]) {
      groups[key] = { total: 0, count: 0 };
    }
    groups[key].total = round2(groups[key].total + value);
    groups[key].count += 1;
  }

  return groups;
}

/**
 * Converts a grouped result object into a sorted array.
 *
 * @param {Object}  groups  - Output of groupAndSum().
 * @param {boolean} desc    - Sort descending when true.
 * @returns {Array<{ key: string, total: number, count: number }>}
 */
function groupedToSortedArray(groups, desc = true) {
  return Object.entries(groups)
    .map(([key, data]) => ({ key, ...data }))
    .sort((a, b) => (desc ? b.total - a.total : a.total - b.total));
}

/**
 * Remove acentos de uma string (NFD) para facilitar matching textual.
 *
 * @param {string} value
 * @returns {string}
 */
function stripAccents(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');
}

/**
 * Gera uma chave canônica para cruzamento de nomes (fornecedor/favorecido).
 *
 * @param {string} value
 * @returns {string}
 */
function normalizeNameKey(value) {
  return stripAccents(value)
    .toUpperCase()
    .replace(/[^A-Z0-9\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const DIVERGENCE_ALERT_THRESHOLD_PCT = 25;
const MIN_MONTHS_FOR_EXACT_ANALYSIS = 2;
const EXACT_MONTHLY_TOLERANCE = 0.01;

// --- Main entry point ---

/**
 * Performs all financial calculations on normalized PRN data.
 *
 * @param {object} normalizedData  - The full normalized payload from normalizer.js.
 * @returns {{ summary, topDespesas, despesasPorCategoria, recebidosPorConta, historyAnalysis, warnings }}
 */
function calculateFinancials(normalizedData) {
  const warnings = [];

  // ------------------------------------------------------------------
  // 1. Defensive defaults – ensure every expected section exists
  // ------------------------------------------------------------------
  const entities  = Array.isArray(normalizedData.entities)  ? normalizedData.entities  : [];
  const expenses  = Array.isArray(normalizedData.expenses)  ? normalizedData.expenses  : [];
  const receipts  = Array.isArray(normalizedData.receipts)  ? normalizedData.receipts  : [];
  const balances  = Array.isArray(normalizedData.balances)  ? normalizedData.balances  : [];
  const history   = normalizedData.history || {};
  const historyRows   = Array.isArray(history.rows)          ? history.rows      : [];
  const historySummary = history.summary || {};

  // ------------------------------------------------------------------
  // 2. Summary calculations
  // ------------------------------------------------------------------

  // Sum all expense valores across every entity
  const totalDespesas = round2(
    expenses.reduce((acc, e) => acc + numProp(e, 'valor'), 0)
  );

  // Sum all receipt valores across every entity
  const totalRecebido = round2(
    receipts.reduce((acc, r) => acc + numProp(r, 'valor'), 0)
  );

  // Aggregate bank and investment balances from entity metadata
  const saldoBancario = round2(
    entities.reduce((acc, e) => acc + numProp(e, 'saldoBancario'), 0)
  );
  const saldoAplicacoes = round2(
    entities.reduce((acc, e) => acc + numProp(e, 'saldoAplicacoes'), 0)
  );

  // Placeholder – future versions will compute the required transfer amount
  const transferenciaNecessaria = 0;

  const summary = {
    totalDespesas,
    totalRecebido,
    saldoBancario,
    saldoAplicacoes,
    transferenciaNecessaria,
  };

  // ------------------------------------------------------------------
  // 3. Top 10 despesas by valor (descending)
  // ------------------------------------------------------------------
  const topDespesas = [...expenses]
    .sort((a, b) => numProp(b, 'valor') - numProp(a, 'valor'))
    .slice(0, 10)
    .map(e => ({
      favorecido: e.favorecido || '',
      categoria:  e.categoria  || '',
      valor:      round2(numProp(e, 'valor')),
      vencimento: e.vencimento || '',
      entity:     e.entity     || '',
    }));

  // ------------------------------------------------------------------
  // 4. Despesas grouped by categoria
  // ------------------------------------------------------------------
  const despesasPorCategoria = groupedToSortedArray(
    groupAndSum(expenses, 'categoria', 'valor')
  ).map(({ key, total, count }) => ({
    categoria: key,
    total,
    count,
  }));

  // ------------------------------------------------------------------
  // 5. Recebidos grouped by contaCorrente
  // ------------------------------------------------------------------
  const recebidosPorConta = groupedToSortedArray(
    groupAndSum(receipts, 'contaCorrente', 'valor')
  ).map(({ key, total, count }) => ({
    contaCorrente: key,
    total,
    count,
  }));

  // ------------------------------------------------------------------
  // 6. History analysis
  // ------------------------------------------------------------------

  // Pass-through scalar fields from the history summary
  const totalRecords = historySummary.totalRecords || 0;
  const periodStart  = historySummary.periodStart  || '';
  const periodEnd    = historySummary.periodEnd    || '';

  // totalPago – sum valorLiquido where situacao === "pago"
  const totalPago = round2(
    historyRows
      .filter(r => (r.situacao || '').toLowerCase() === 'pago')
      .reduce((acc, r) => acc + numProp(r, 'valorLiquido'), 0)
  );

  // totalAtrasado – sum valorLiquido where situacao === "atrasado"
  const totalAtrasado = round2(
    historyRows
      .filter(r => (r.situacao || '').toLowerCase() === 'atrasado')
      .reduce((acc, r) => acc + numProp(r, 'valorLiquido'), 0)
  );

  // topCategorias – group history rows by categoria, sum valorLiquido, top 10
  const historyCatGroups = groupAndSum(historyRows, 'categoria', 'valorLiquido');
  const topCategorias = groupedToSortedArray(historyCatGroups)
    .slice(0, 10)
    .map(({ key, total }) => ({ categoria: key, total }));

  // topFornecedores – group history rows by fornecedor, sum valorLiquido, top 10
  const historyForGroups = groupAndSum(historyRows, 'fornecedor', 'valorLiquido');
  const topFornecedores = groupedToSortedArray(historyForGroups)
    .slice(0, 10)
    .map(({ key, total }) => ({ fornecedor: key, total }));

  // distribuicaoContas – group history rows by contaCorrente, sum valorLiquido
  const historyContaGroups = groupAndSum(historyRows, 'contaCorrente', 'valorLiquido');
  const totalHistoricoContas = round2(
    Object.values(historyContaGroups).reduce((acc, d) => acc + numProp(d, 'total'), 0)
  );

  const distribuicaoContas = groupedToSortedArray(historyContaGroups)
    .map(({ key, total }) => ({
      conta: key,
      total,
      percentual: totalHistoricoContas > 0 ? round2((total / totalHistoricoContas) * 100) : 0,
    }));

  const historyAnalysis = {
    totalRecords,
    periodStart,
    periodEnd,
    totalPago,
    totalAtrasado,
    topCategorias,
    topFornecedores,
    distribuicaoContas,
  };

  // ------------------------------------------------------------------
  // 6.1 Cruzamento principal: nomes da diária x histórico por mês
  // ------------------------------------------------------------------
  const dailyByName = {};
  for (const e of expenses) {
    const nome = String(e.favorecido || e.fornecedor || '').trim();
    const valor = round2(numProp(e, 'valor'));

    if (!nome || nome.toUpperCase() === 'N/D') continue;
    if (valor === 0) continue;

    const key = normalizeNameKey(nome);
    if (!key) continue;

    if (!dailyByName[key]) {
      dailyByName[key] = {
        nome,
        valorDia: 0,
        qtdTitulosDia: 0,
      };
    }

    dailyByName[key].valorDia = round2(dailyByName[key].valorDia + valor);
    dailyByName[key].qtdTitulosDia += 1;
  }

  const historyByName = {};
  const monthSet = new Set();
  for (const r of historyRows) {
    const situacao = String(r.situacao || '').toLowerCase();
    // Para o objetivo atual, considerar apenas pagamentos efetivados
    if (!(situacao === 'pago' || situacao === 'pago_parcialmente' || situacao.includes('pago'))) {
      continue;
    }

    const nome = String(r.fornecedor || r.favorecido || '').trim();
    if (!nome) continue;

    const valor = round2(numProp(r, 'valorLiquido'));
    if (valor === 0) continue;

    const dataRef = r.ultimoPagamento || r.vencimento || r.previsao || '';
    const monthKey = typeof dataRef === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(dataRef)
      ? dataRef.slice(0, 7)
      : '';

    const key = normalizeNameKey(nome);
    if (!key) continue;

    if (!historyByName[key]) {
      historyByName[key] = {
        nome,
        totalHistorico: 0,
        qtdHistorico: 0,
        ultimoPagamento: '',
        meses: {},
      };
    }

    historyByName[key].totalHistorico = round2(historyByName[key].totalHistorico + valor);
    historyByName[key].qtdHistorico += 1;

    if (monthKey) {
      monthSet.add(monthKey);
      historyByName[key].meses[monthKey] = round2((historyByName[key].meses[monthKey] || 0) + valor);
    }

    if (typeof dataRef === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(dataRef)) {
      if (!historyByName[key].ultimoPagamento || dataRef > historyByName[key].ultimoPagamento) {
        historyByName[key].ultimoPagamento = dataRef;
      }
    }
  }

  const months = Array.from(monthSet).sort();
  const crossRows = Object.entries(dailyByName)
    .map(([key, d]) => {
      const h = historyByName[key] || {
        totalHistorico: 0,
        qtdHistorico: 0,
        ultimoPagamento: '',
        meses: {},
      };

      const meses = {};
      for (const m of months) {
        meses[m] = round2(h.meses[m] || 0);
      }

      const monthlyValues = Object.values(meses)
        .map((v) => round2(Number(v) || 0))
        .filter((v) => v > 0);

      const qtdMesesComPagamento = monthlyValues.length;
      const temHistorico = h.qtdHistorico > 0 && h.totalHistorico > 0;

      const mediaHistoricaMensal = temHistorico && qtdMesesComPagamento > 0
        ? round2(monthlyValues.reduce((acc, v) => acc + v, 0) / qtdMesesComPagamento)
        : 0;

      const minMensal = qtdMesesComPagamento > 0 ? Math.min(...monthlyValues) : 0;
      const maxMensal = qtdMesesComPagamento > 0 ? Math.max(...monthlyValues) : 0;

      const pagamentoExatoMensal = temHistorico
        && qtdMesesComPagamento >= MIN_MONTHS_FOR_EXACT_ANALYSIS
        && Math.abs(maxMensal - minMensal) <= EXACT_MONTHLY_TOLERANCE;

      const pagamentoDiferenteMensal = temHistorico && !pagamentoExatoMensal;

      const divergenciaPct = temHistorico && mediaHistoricaMensal > 0
        ? round2(((round2(d.valorDia) - mediaHistoricaMensal) / mediaHistoricaMensal) * 100)
        : null;

      const alertaDivergencia25 = divergenciaPct !== null
        && Math.abs(divergenciaPct) > DIVERGENCE_ALERT_THRESHOLD_PCT;

      const direcaoDivergencia = divergenciaPct === null
        ? 'sem_base'
        : divergenciaPct > 0
          ? 'acima'
          : divergenciaPct < 0
            ? 'abaixo'
            : 'estavel';

      const grupoMensal = !temHistorico
        ? 'sem_historico'
        : pagamentoExatoMensal
          ? 'exato'
          : qtdMesesComPagamento < MIN_MONTHS_FOR_EXACT_ANALYSIS
            ? 'historico_insuficiente'
            : 'diferente';

      return {
        nome: d.nome,
        valorDia: round2(d.valorDia),
        qtdTitulosDia: d.qtdTitulosDia,
        totalHistorico: round2(h.totalHistorico),
        qtdHistorico: h.qtdHistorico,
        ultimoPagamento: h.ultimoPagamento || null,
        meses,
        qtdMesesComPagamento,
        temHistorico,
        mediaHistoricaMensal,
        divergenciaPct,
        alertaDivergencia25,
        direcaoDivergencia,
        pagamentoExatoMensal,
        pagamentoDiferenteMensal,
        grupoMensal,
      };
    })
    .sort((a, b) => b.valorDia - a.valorDia);

  const summarizeGroup = (rows) => ({
    totalNomes: rows.length,
    totalValorDia: round2(rows.reduce((acc, r) => acc + round2(r.valorDia), 0)),
    totalHistorico: round2(rows.reduce((acc, r) => acc + round2(r.totalHistorico), 0)),
    rows,
  });

  const comHistoricoRows = crossRows.filter((r) => r.temHistorico);
  const semHistoricoRows = crossRows.filter((r) => !r.temHistorico);
  const exatoTodosMesesRows = crossRows.filter((r) => r.temHistorico && r.pagamentoExatoMensal);
  const diferenteEntreMesesRows = crossRows.filter((r) => r.temHistorico && !r.pagamentoExatoMensal);
  const alertaAnaliseManualRows = crossRows.filter((r) => r.alertaDivergencia25);

  const crossAnalysis = {
    months,
    rows: crossRows,
    config: {
      divergenceThresholdPct: DIVERGENCE_ALERT_THRESHOLD_PCT,
      minMonthsForExactAnalysis: MIN_MONTHS_FOR_EXACT_ANALYSIS,
      divergenceBase: 'media_historica_mensal_com_pagamento',
    },
    totalNomesDia: crossRows.length,
    totalValorDia: round2(crossRows.reduce((acc, r) => acc + r.valorDia, 0)),
    totalHistoricoCruzado: round2(crossRows.reduce((acc, r) => acc + r.totalHistorico, 0)),
    groups: {
      comHistorico: summarizeGroup(comHistoricoRows),
      semHistorico: summarizeGroup(semHistoricoRows),
      exatoTodosMeses: summarizeGroup(exatoTodosMesesRows),
      diferenteEntreMeses: summarizeGroup(diferenteEntreMesesRows),
      alertaAnaliseManual: summarizeGroup(alertaAnaliseManualRows),
    },
  };

  if (alertaAnaliseManualRows.length > 0) {
    warnings.push(
      `${alertaAnaliseManualRows.length} pagamento(s) diário(s) com divergência acima de ${DIVERGENCE_ALERT_THRESHOLD_PCT}% versus média histórica mensal.`
    );
  }

  // ------------------------------------------------------------------
  // 7. Warnings / alerts
  // ------------------------------------------------------------------

  // Warn if totalRecebido is more than 30% below totalDespesas
  if (totalDespesas > 0) {
    const ratio = totalRecebido / totalDespesas;
    if (ratio < 0.70) {
      const deficitPercent = round2((1 - ratio) * 100);
      warnings.push(
        `Receita significativamente inferior a despesas (${deficitPercent}% abaixo). ` +
        `Recebido: R$ ${totalRecebido.toFixed(2)} | Despesas: R$ ${totalDespesas.toFixed(2)}`
      );
    }
  }

  // Warn if aggregate saldoBancario is negative
  if (saldoBancario < 0) {
    warnings.push(
      `Saldo bancario total negativo: R$ ${saldoBancario.toFixed(2)}`
    );
  }

  // Warn for each entity with a negative saldoBancario
  for (const entity of entities) {
    const entitySaldo = numProp(entity, 'saldoBancario');
    if (entitySaldo < 0) {
      warnings.push(
        `Entidade "${entity.label || entity.code}" com saldo bancario negativo: R$ ${entitySaldo.toFixed(2)}`
      );
    }
  }

  // Carry forward any warnings that arrived with the input (idempotent merge)
  if (Array.isArray(normalizedData.warnings)) {
    for (const w of normalizedData.warnings) {
      const msg = typeof w === 'string' ? w : (w && w.message ? w.message : '');
      if (msg && !warnings.includes(msg)) {
        warnings.push(msg);
      }
    }
  }

  // ------------------------------------------------------------------
  // 8. Return the complete result
  // ------------------------------------------------------------------
  return {
    summary,
    topDespesas,
    despesasPorCategoria,
    recebidosPorConta,
    historyAnalysis,
    crossAnalysis,
    warnings,
  };
}

